import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"太日阳莽体","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/5.通用类/太日阳莽体.md","filePath":"4.资源分区/1.血统与训练/5.通用类/太日阳莽体.md"}'),o={name:"4.资源分区/1.血统与训练/5.通用类/太日阳莽体.md"};function p(d,e,_,l,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"太日阳莽体",tabindex:"-1"},[n("太日阳莽体 "),r("a",{class:"header-anchor",href:"#太日阳莽体","aria-label":'Permalink to "太日阳莽体"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌030")])])],-1),s('<h1 id="太日阳莽体-1" tabindex="-1">太日阳莽体 <a class="header-anchor" href="#太日阳莽体-1" aria-label="Permalink to &quot;太日阳莽体&quot;">​</a></h1><p>太日阳莽体<br> 魔幻本质<br> 血统<br> 描述：他的左眼，落在地上，化作一个少年郎。他有一头的金发，健壮的身躯，他一出现，就拜倒在人祖的脚下，大叫：“人祖啊，我的父亲，我是您的大儿子太日阳莽。”<br> 拥有该血统后，你的发色与双眸将转变为耀眼的金色。</p><p>D+600<br> 该等级下，太日阳莽体获得【太日道心】特性<br> 【太日道心】：已得酒中趣，勿为醒者传。每当太日阳莽体经历一场影片，你就额外获得5米的移动速度。<br> 以此成长三场影片后，太日阳莽体在移动时可以调用自然间的宇道道痕，顷刻穿梭一段空间，这意味着如今太日阳莽体在移动时可以传送到移动距离内的任意一点（前提是你能明确定位那个位置），这是一个时空来源的C级传送移动特性。<br> 在获得传送移动特性后，太日阳莽体不会再因经历影片而获得移速成长。<br> 宇道对太日阳莽体的青睐体现在方方面面，纵使是刚刚觉醒，依然能够具有1点远程伤害吸收，并且免疫B级异空间效果。<br> 同时，购买该血统后你无法以任何形式免疫坠落伤害。</p><p>C+1200<br> 该等级下，太日阳莽体获得【不平常】特性<br> 【不平常】：如今，太日阳莽体在战斗中可以引起周遭环境中的宇道道痕共鸣，攻击可以透过道痕，直接穿梭至敌人身边发出，这意味着太日阳莽体攻击具有C级时空来源的传送攻击特性，并在进行传送攻击时，使攻击附带有C级时空来源的措手不及效果。<br> 如今，每经历一场影片，太日阳莽体就可以获得额外的声望，在购买该等级时从获得善名或恶名中进行选择；若选择恶名，则每场影片结束后都会获得额外5点恶名。<br> 若选择善名，每场影片获得的声望不变，但每受益三场影片后，下一场影片不会获得声望，转而扩大3点蛊元能量池的能量上限，与声望一样，每扩大三次能量池，就会有一场影片结束后不会受益。</p><p>B级<br> B+2400<br> 该等级下，太日阳莽体获得【不虚荣】特性<br> 【不虚荣】：不是我聪明。是爱慕虚荣的人，都会变得愚蠢。他们常常为了虚无的美丽，而默默忍受痛楚，放弃真正应该追求的东西。<br> 现在，太日阳莽夫体的双眼如烈日般熊熊燃烧，其视觉提升为强感知，并具有B级别、特异本质的侦测等级以及【透视】效果。<br> 结合在一次传送攻击中，太日阳莽体可以令那次攻击额外附带有B级时空来源的放逐效果，承受攻击的目标需以攻击出目为dc进行反射豁免，豁免失败则将被攻击调动周遭道痕结成的宇道空间困住，从而在一轮内脱离原先位面。<br> 太日阳莽体从【太日道心】中获得的异空间免疫等级提升至A级。</p><p>A级<br> A+4800<br> 该等级下，太日阳莽体获得【自我】特性<br> 【自我】：思想蛊瞧了一眼，便道：“嗯，你这对翅膀叫做自我，每个人都有自我思想。这双翅膀非常灵便，也非常自由。但是你要小心，不要被阳光过度照射，否则自我不是膨胀变大，就是缩减变小。”<br> 太日阳莽体对于宇道的掌控力加深更多，【不虚荣】特性中的异空间效果提升为A级，道痕组成的异空间可以承受的放逐时间延长为一场景，异空间内禁止以A级及以下传送效果，同时，被放逐至异空间的单位失去所有可用动作。<br> 你施展的传送攻击将再额外附带有【超级贯穿】特性。<br> 经历一场影片后，【自我】特性转变为【自傲】<br> 【自傲】：太日阳莽哈哈一笑：“蛊啊，你就放心吧。我连平凡深渊都闯了过去，在毛民那里也能求生，有了名声蛊，又勘破了虚荣。荣耀的阳光，也不能拿我怎样。”<br> 基于【自我】特性，太日阳莽体可以更加灵活地操作环境中的宇道道痕影响敌人的行动，在进行传送攻击时，太日阳莽体的攻击具有A级别、时空来源的无视闪避防御的效果。<br> 在一场战胜过至少是同级别的敌人，并在结束时达到【传奇】评分的影片之后，【自傲】特性将转变为【不自满】</p><p>【不自满】：身后自我的翅膀，越长越大，最终比他的整个人还要庞大。太日阳莽振翅飞翔的速度，也越来越快。<br> 此时，太日阳莽体的头发将如太阳般无风自动，熊熊燃烧。基于【自傲】特性，现在太日阳莽体在战斗中，每轮都可以免受一次针对自身的单体伤害,这是一个A级别、命运来源的无敌效果。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=a(o,[["render",p]]);export{f as __pageData,m as default};
